SELECT [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].No_, [Sales Line].[delete reason], [Sales Line].[Model Item No_], [Sales Line].[Variable Code 01], Sum(Val([Sales Line.No_ of Pairs])) AS PairsSold, [Sales Line].[Currency Code], Sum(IIf([Sales Line.document type]=1,(Val([Sales Line.Line Amount])-Val([Sales Line.Inv_ Discount Amount])),-(Val([Sales Line.Line Amount])-Val([Sales Line.Inv_ Discount Amount])))) AS ValueSold, ItemMasterData_EXWFOB_step0.Costo, Sum(Val([Sales Line.No_ of Pairs])*[costo]) AS TotCosto, [Sales Line].Type, [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[Shortcut Dimension 1 Code], [Sales Header].[Selling Season Code]
FROM ([Sales Header] INNER JOIN [Sales Line] ON ([Sales Header].No_ = [Sales Line].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Line].[Document Type])) LEFT JOIN ItemMasterData_EXWFOB_step0 ON ([Sales Line].[Constant Variable Code] = ItemMasterData_EXWFOB_step0.[Variable Code 01]) AND ([Sales Line].No_ = ItemMasterData_EXWFOB_step0.[Model Item No_])
GROUP BY [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].No_, [Sales Line].[delete reason], [Sales Line].[Model Item No_], [Sales Line].[Variable Code 01], [Sales Line].[Currency Code], ItemMasterData_EXWFOB_step0.Costo, [Sales Line].Type, [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[Shortcut Dimension 1 Code], [Sales Header].[Selling Season Code]
HAVING ((([Sales Header].No_)="OV-24/06160" Or ([Sales Header].No_)="OV-24/06153" Or ([Sales Header].No_)="OV-24/06122" Or ([Sales Header].No_)="OV-24/06119" Or ([Sales Header].No_)="OV-24/06118" Or ([Sales Header].No_)="OV-24/06117" Or ([Sales Header].No_)="OV-24/06075" Or ([Sales Header].No_)="OV-24/06063" Or ([Sales Header].No_)="OV-24/06058" Or ([Sales Header].No_)="OV-24/06057" Or ([Sales Header].No_)="OV-24/06056" Or ([Sales Header].No_)="OV-24/06052" Or ([Sales Header].No_)="OV-24/06051" Or ([Sales Header].No_)="OV-24/06049") AND (([Sales Line].[delete reason])="") AND (([Sales Line].Type)=19 Or ([Sales Line].Type)=20));

